#include <threads.h>
#include <hardware.h>
#include <terminals.h>
#include <stdio.h>

#define TERMINAL_MAX_LINE 512
#define ECHO_BUFFER_SIZE (TERMINAL_MAX_LINE * 3)

/*
 * Terminal state structure.
 * Only one monitor is used for all terminals.
 */
struct terminal_state {
    int initialized;
    struct termstat stats;

    /* Input buffer */
    char in_buf[TERMINAL_MAX_LINE];
    int in_head;
    int in_tail;
    int in_count;
    int in_lines;     /* number of complete lines in in_buf */
    cond_id_t in_cv;

    /* Output state */
    int tx_busy;
    char echo_buf[ECHO_BUFFER_SIZE];
    int echo_head;
    int echo_tail;
    int echo_count;

    /* WriteTerminal state */
    int write_active;
    cond_id_t write_lock_cv;
    cond_id_t write_done_cv;

    /* Current WriteTerminal request */
    const char *user_write_buf;
    int user_write_len;
    int user_write_pos;
    int write_nl_state; /* 1 if we just sent \r for a \n and need to send \n */
};

static struct terminal_state terminals[NUM_TERMINALS];
static int driver_initialized = 0;

/* Internal procedure to attempt starting a transmission */
static void try_transmit(int term);

int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();
    if (driver_initialized) return -1;

    for (int i = 0; i < NUM_TERMINALS; i++) {
        terminals[i].initialized = 0;
        terminals[i].stats.tty_in = -1;
        terminals[i].stats.tty_out = -1;
        terminals[i].stats.user_in = -1;
        terminals[i].stats.user_out = -1;
    }

    driver_initialized = 1;
    return 0;
}

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();
    if (!driver_initialized) return -1;
    if (term < 0 || term >= NUM_TERMINALS) return -1;
    if (terminals[term].initialized) return -1;

    if (InitHardware(term) < 0) return -1;

    terminals[term].initialized = 1;
    terminals[term].stats.tty_in = 0;
    terminals[term].stats.tty_out = 0;
    terminals[term].stats.user_in = 0;
    terminals[term].stats.user_out = 0;

    terminals[term].in_head = 0;
    terminals[term].in_tail = 0;
    terminals[term].in_count = 0;
    terminals[term].in_lines = 0;
    terminals[term].in_cv = CondCreate();

    terminals[term].tx_busy = 0;
    terminals[term].echo_head = 0;
    terminals[term].echo_tail = 0;
    terminals[term].echo_count = 0;

    terminals[term].write_active = 0;
    terminals[term].write_lock_cv = CondCreate();
    terminals[term].write_done_cv = CondCreate();

    terminals[term].user_write_buf = NULL;
    terminals[term].user_write_len = 0;
    terminals[term].user_write_pos = 0;
    terminals[term].write_nl_state = 0;

    return 0;
}

int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();
    if (!driver_initialized) return -1;
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) return -1;
    if (buflen < 0) return -1;
    if (buflen == 0) return 0;
    if (buf == NULL) return -1;

    /* Block until at least one complete line is available */
    while (terminals[term].in_lines == 0) {
        CondWait(terminals[term].in_cv);
    }

    int count = 0;
    while (count < buflen && terminals[term].in_count > 0) {
        char c = terminals[term].in_buf[terminals[term].in_head];
        buf[count++] = c;
        terminals[term].in_head = (terminals[term].in_head + 1) % TERMINAL_MAX_LINE;
        terminals[term].in_count--;

        if (c == '\n') {
            terminals[term].in_lines--;
            break;
        }
    }

    /* If there are more lines, signal the next waiting ReadTerminal call */
    if (terminals[term].in_lines > 0) {
        CondSignal(terminals[term].in_cv);
    }

    terminals[term].stats.user_out += count;
    return count;
}

int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();
    if (!driver_initialized) return -1;
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) return -1;
    if (buflen < 0) return -1;
    if (buflen == 0) {
        terminals[term].stats.user_in += 0; /* although buflen is 0 */
        return 0;
    }
    if (buf == NULL) return -1;

    /* Serialize concurrent WriteTerminal calls to the same terminal */
    while (terminals[term].write_active) {
        CondWait(terminals[term].write_lock_cv);
    }

    terminals[term].write_active = 1;
    terminals[term].user_write_buf = buf;
    terminals[term].user_write_len = buflen;
    terminals[term].user_write_pos = 0;
    terminals[term].write_nl_state = 0;
    terminals[term].stats.user_in += buflen;

    /* Start transmission if hardware is idle and no echoes are pending */
    if (!terminals[term].tx_busy) {
        try_transmit(term);
    }

    /* Block until all characters are transmitted */
    while (terminals[term].user_write_len > 0 || terminals[term].write_nl_state == 1) {
        CondWait(terminals[term].write_done_cv);
    }

    terminals[term].write_active = 0;
    CondSignal(terminals[term].write_lock_cv);

    return buflen;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();
    if (!driver_initialized) return -1;
    if (stats == NULL) return -1;

    for (int i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terminals[i].stats;
    }
    return 0;
}

/*
 * Internal procedure to send the next character to the hardware.
 * Echo has priority over WriteTerminal.
 */
static void
try_transmit(int term)
{
    if (terminals[term].echo_count > 0) {
        char c = terminals[term].echo_buf[terminals[term].echo_head];
        terminals[term].echo_head = (terminals[term].echo_head + 1) % ECHO_BUFFER_SIZE;
        terminals[term].echo_count--;
        WriteDataRegister(term, c);
        terminals[term].stats.tty_out++;
        terminals[term].tx_busy = 1;
    } else if (terminals[term].write_active && (terminals[term].user_write_len > 0 || terminals[term].write_nl_state == 1)) {
        char c;
        if (terminals[term].write_nl_state == 1) {
            c = '\n';
            terminals[term].write_nl_state = 0;
            terminals[term].user_write_pos++;
            terminals[term].user_write_len--;
        } else {
            c = terminals[term].user_write_buf[terminals[term].user_write_pos];
            if (c == '\n') {
                c = '\r';
                terminals[term].write_nl_state = 1;
            } else {
                terminals[term].user_write_pos++;
                terminals[term].user_write_len--;
            }
        }
        WriteDataRegister(term, c);
        terminals[term].stats.tty_out++;
        terminals[term].tx_busy = 1;
    } else {
        terminals[term].tx_busy = 0;
        CondSignal(terminals[term].write_done_cv);
    }
}

void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) return;

    char c = ReadDataRegister(term);
    terminals[term].stats.tty_in++;

    if (c == '\r' || c == '\n') {
        if (terminals[term].in_count < TERMINAL_MAX_LINE) {
            terminals[term].in_buf[terminals[term].in_tail] = '\n';
            terminals[term].in_tail = (terminals[term].in_tail + 1) % TERMINAL_MAX_LINE;
            terminals[term].in_count++;
            terminals[term].in_lines++;

            /* Echo \r\n */
            if (terminals[term].echo_count + 2 <= ECHO_BUFFER_SIZE) {
                terminals[term].echo_buf[terminals[term].echo_tail] = '\r';
                terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                terminals[term].echo_buf[terminals[term].echo_tail] = '\n';
                terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                terminals[term].echo_count += 2;
            }
            CondSignal(terminals[term].in_cv);
        } else {
            /* Input buffer full - drop char and optionally ring bell */
            if (terminals[term].echo_count + 1 <= ECHO_BUFFER_SIZE) {
                terminals[term].echo_buf[terminals[term].echo_tail] = '\a';
                terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                terminals[term].echo_count++;
            }
        }
    } else if (c == '\b' || c == '\177') {
        if (terminals[term].in_count > 0) {
            int last_idx = (terminals[term].in_tail - 1 + TERMINAL_MAX_LINE) % TERMINAL_MAX_LINE;
            /* Backspace only affects the current line being typed */
            if (terminals[term].in_buf[last_idx] != '\n') {
                terminals[term].in_tail = last_idx;
                terminals[term].in_count--;
                /* Echo \b space \b */
                if (terminals[term].echo_count + 3 <= ECHO_BUFFER_SIZE) {
                    terminals[term].echo_buf[terminals[term].echo_tail] = '\b';
                    terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                    terminals[term].echo_buf[terminals[term].echo_tail] = ' ';
                    terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                    terminals[term].echo_buf[terminals[term].echo_tail] = '\b';
                    terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                    terminals[term].echo_count += 3;
                }
            }
        }
    } else {
        if (terminals[term].in_count < TERMINAL_MAX_LINE) {
            terminals[term].in_buf[terminals[term].in_tail] = c;
            terminals[term].in_tail = (terminals[term].in_tail + 1) % TERMINAL_MAX_LINE;
            terminals[term].in_count++;
            /* Echo the character */
            if (terminals[term].echo_count + 1 <= ECHO_BUFFER_SIZE) {
                terminals[term].echo_buf[terminals[term].echo_tail] = c;
                terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                terminals[term].echo_count++;
            }
        } else {
            /* Input buffer full - drop char and optionally ring bell */
            if (terminals[term].echo_count + 1 <= ECHO_BUFFER_SIZE) {
                terminals[term].echo_buf[terminals[term].echo_tail] = '\a';
                terminals[term].echo_tail = (terminals[term].echo_tail + 1) % ECHO_BUFFER_SIZE;
                terminals[term].echo_count++;
            }
        }
    }

    if (!terminals[term].tx_busy) {
        try_transmit(term);
    }
}

void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();
    if (term < 0 || term >= NUM_TERMINALS || !terminals[term].initialized) return;

    terminals[term].tx_busy = 0;
    try_transmit(term);
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <threads.h>
#include <terminals.h>
#include <hardware.h>

void reader_thread(void *arg) {
    int term = (int)(long)arg;
    char buf[100];
    int n;

    printf("Reader thread started for terminal %d\n", term);
    n = ReadTerminal(term, buf, 10);
    if (n < 0) {
        printf("ReadTerminal error\n");
        return;
    }
    buf[n] = '\0';
    printf("Read %d chars: [%s]\n", n, buf);

    n = ReadTerminal(term, buf, 10);
    if (n < 0) {
        printf("ReadTerminal error\n");
        return;
    }
    buf[n] = '\0';
    printf("Read %d chars: [%s]\n", n, buf);
}

int main() {
    InitTerminalDriver();
    InitTerminal(0);

    // We can't easily simulate hardware interrupts from a user program
    // without the library's help, but we can at least test that 
    // Init and stats work, and that ReadTerminal blocks.

    // Since this is an agent test, I'll rely on the fact that 
    // the test runner can provide input to the terminals.

    ThreadCreate(reader_thread, (void *)0);

    ThreadWaitAll();
    return 0;
}

